import {useState} from 'react';
import swal from "sweetalert";
const Myregister = () =>{

    let [name, pickname] = useState("");
    let [mobile, pickmobile] = useState("");
    let [email, pickemail] = useState("");
    let [password, pickpassword] = useState("");
    let [gender, pickgender] = useState("");
    let [source, picksource] = useState("");
    const state = []

    const save = () =>{
       let url = "http://localhost:1234/account";
       let sellerdata = 
       {
          sname: name,
          smobile : mobile,
          semail : email,
          spassword : password,
          sgender : gender,
          ssource : source
       } 

       let postdata = 
       {
        headers : {'Content-type' : 'application/json'},
        method: "POST",
        body : JSON.stringify(sellerdata)
       }

       fetch(url, postdata)
       .then(responsedata => responsedata.json())
       .then(data => {
        swal("Account Created Successfully !!", "", "success");
        window.location.href = "http://localhost:3000/#/login";
       })
    }

    return(
                       <div className="container mt-4">
                        <div className="row">
                             <div className="col-lg-3"></div>
                            <div className="col-lg-6">
                                    <div className="p-4 shadow-lg rounded">
                                     <h2 className="text-center">Create New Account</h2>
                                    
                                    <div className='mb-3'>
                                       <label><b>User's Name</b> </label>
                                       <input type="text" placeholder="Enter your name" className="form-control"  onChange={obj=> pickname(obj.target.value)} value={name}/>
                                       </div>

                                       <div className='mb-3'>
                                       <label><b>User's Email</b> </label>
                                       <input type="email" placeholder="Enter your Email" className="form-control" value={email} onChange={obj=>pickemail(obj.target.value)}/>
                                       </div>


                                       <div className='mb-3'>
                                       <label><b>User's Phone</b> </label>
                                       <input type="number" placeholder="Enter your Phone no." className="form-control" value={mobile} onChange={obj=>pickmobile(obj.target.value)}/>
                                       </div>


                                       <div className='mb-3'>
                                       <label><b>User's Password</b> </label>
                                       <input type="password" placeholder="Enter your Password" className="form-control" value={password} onChange={obj=> pickpassword(obj.target.value)}/>
                                       </div>

                                     <div className='mb-3'>
                                       <label className='m-2'><b>Gender</b> </label>

                                       <label className='m-2'>
                                             <input type="radio" name="gender" value="Male" onChange={obj=> pickgender(obj.target.value)}/>Male
                                       </label>

                                           <label className='m-2'>
                                          <input type="radio"  name="gender" value="Female"  onChange={obj=> pickgender(obj.target.value)}/>Female
                                          </label>

                                          <label className='m-2'>
                                          <input type="radio" name="gender" value="Other"   onChange={obj=> pickgender(obj.target.value)}/>Others
                                          </label>

                                    </div>

                                    <div className='mb-3'>
                                       <label className='m-2'><b>How did you hear about us? </b> </label>

                                        <div>
                                             <input type="checkbox" className='m-2' name="source" value="Linkedin" onChange={obj=> picksource(obj.target.value)}/>Linkedin
                                       
  
                                          <input type="checkbox" className='m-2' name="source" value="Friends"  onChange={obj=> picksource(obj.target.value)}/>Friends
                                         
                                            <input type="checkbox" className='m-2' name="source" value="Job-portal"   onChange={obj=> picksource(obj.target.value)}/>Job Portal
                                         
                                          <input type="checkbox" className='m-2' name="source" value="Others"   onChange={obj=> picksource(obj.target.value)}/>Others
                                          </div>
                                    </div>

                                    <select
                                       className="form-control"
                                       onChange={(obj) => pickcity(obj.target.value)}
                                       value={city}
                                       >
                                       <option value=""> select one </option>
                                       <option value="Feature">Mumbai </option>
                                       <option value="Pricing">Pune</option>
                                       <option value="Usability">Ahemdabad</option>
                                    </select>
                                    
                                    <div className="row">
     {
          allproduct.slice(offset, offset + PER_PAGE).map((product, index) => {

          if(product.name.toLowerCase().includes(keyword.toLowerCase()))
          {
            // it cheks what user type in search box include in the product or not
            return (
              <div className="col-lg-3 mb-4" key={index}>
                <div className="p-3 text-center shadow">
                  <h4 className="text-info mb-3"> {product.name} </h4>
                  <img
                    src={product.photo}
                    className="rounded"
                    height="140"
                    width="100%"
                  />
                  <p className="mt-3"> {product.details} </p>
                  <p className="m-3">Rs. {product.price} </p>
                  <p className="text-center">
                    <button
                      className="btn btn-danger"
                      onClick={addtoCart.bind(this, product)}
                    >
                      <i className="fa fa-shopping-cart"></i>Add to cart
                    </button>
                  </p>
                </div>
              </div>
            );
          }
       })
      }
        </div>

                                     <div className="text-center mt-3"> <button className="btn btn-danger" onClick={save}> Register</button></div>
                                      </div>
                            </div>
                            <div className="col-lg-3"></div>
                         </div>
                      </div>
    )
}

export default Myregister;
